import{_ as r,c as i,o as n,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.38: Experimental Markdown Component, Multiple Fixes","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.38.md","filePath":"en/changelog/v1.1.38.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.1.38.md"};function s(l,a,d,u,p,h){return n(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-38-experimental-markdown-component-multiple-fixes" tabindex="-1">v1.1.38: Experimental Markdown Component, Multiple Fixes <a class="header-anchor" href="#v1-1-38-experimental-markdown-component-multiple-fixes" aria-label="Permalink to “v1.1.38: Experimental Markdown Component, Multiple Fixes”">​</a></h1><p><strong>Release Date</strong>: January 28, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update adds an experimental OpenTUI Markdown component and fixes multiple tool and plugin related issues.</p><hr><h2 id="new-feature-opentui-markdown-component" tabindex="-1">New Feature: OpenTUI Markdown Component <a class="header-anchor" href="#new-feature-opentui-markdown-component" aria-label="Permalink to “New Feature: OpenTUI Markdown Component”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added an experimental OpenTUI Markdown component in the Desktop app for a better Markdown rendering experience.</p><h3 id="how-to-enable" tabindex="-1">How to enable? <a class="header-anchor" href="#how-to-enable" aria-label="Permalink to “How to enable?”">​</a></h3><p>This feature is experimental and needs to be enabled through configuration. Once enabled, you&#39;ll get smoother Markdown rendering effects.</p><hr><h2 id="bug-fix-agents-md-duplicate-loading" tabindex="-1">Bug Fix: AGENTS.md Duplicate Loading <a class="header-anchor" href="#bug-fix-agents-md-duplicate-loading" aria-label="Permalink to “Bug Fix: AGENTS.md Duplicate Loading”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When executing tools in parallel, AGENTS.md files might be loaded multiple times, affecting performance.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed this issue. AGENTS.md is now only loaded once, improving parallel execution efficiency.</p><hr><h2 id="bug-fix-partupdated-unsubscription" tabindex="-1">Bug Fix: PartUpdated Unsubscription <a class="header-anchor" href="#bug-fix-partupdated-unsubscription" aria-label="Permalink to “Bug Fix: PartUpdated Unsubscription”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>PartUpdated event subscriptions in TaskTool were sometimes not properly unsubscribed, causing memory leaks.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @goniz&#39;s fix, all subscriptions are now properly unsubscribed.</p><hr><h2 id="bug-fix-cli-brand-display" tabindex="-1">Bug Fix: CLI Brand Display <a class="header-anchor" href="#bug-fix-cli-brand-display" aria-label="Permalink to “Bug Fix: CLI Brand Display”">​</a></h2><h3 id="previous-issue-2" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-2" aria-label="Permalink to “Previous Issue”">​</a></h3><p>The CLI brand identity display had issues.</p><h3 id="current-status-2" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-2" aria-label="Permalink to “Current Status”">​</a></h3><p>Thanks to community contributor @mynameistito&#39;s fix, the CLI brand identity now displays correctly.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using CLI</td><td>✅ Recommended upgrade (brand display fix)</td></tr><tr><td>Focused on performance</td><td>✅ Recommended upgrade (memory leak fix)</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',33),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Prevent AGENTS.md from being loaded multiple times during parallel tool execution</li><li>Bump plugin version</li><li>Ensure unsubscribe from PartUpdated is always called in TaskTool (@goniz)</li><li>Restore brand integrity of CLI wordmark (@mynameistito)</li><li>Add experimental OpenTUI markdown component to app (@remorses)</li></ul><p><strong>Thank you to 4 community contributors:</strong></p><p>@remorses:</p><ul><li>feat(app): use opentui markdown component behind experimental flag (#10900)</li></ul><p>@jamesmurdza:</p><ul><li>docs: add Daytona OpenCode plugin to ecosystem (#10917)</li></ul><p>@mynameistito:</p><ul><li>fix(cli): restore brand integrity of CLI wordmark (#10912)</li></ul><p>@goniz:</p><ul><li>fix(opencode): ensure unsub(PartUpdated) is always called in TaskTool (#9992)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=r(o,[["render",s]]);export{m as __pageData,b as default};
